/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Features:
 * - Phone number validation (E.164 format)
 * - Plain-text message formatting from NotificationPayload
 * - Pluggable transport (swap SmsTransport for real provider like Twilio)
 * - Retry support with configurable attempts
 *
 * NOTE: User preferences (src/models/user-preferences.ts) currently only
 * model email preferences (emailEnabled, emailFrequency). The preferences
 * system needs to be updated to support per-channel settings (e.g. smsEnabled,
 * per-channel frequency) before SMS notifications can be properly gated by
 * user preference. See the TODO in this file and the warning posted to Twining.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the SMS adapter.
 */
export interface SmsConfig {
  fromNumber: string;
  maxRetries?: number;
}

/**
 * A formatted SMS message ready for transport.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Transport interface — swap this implementation for a real
 * SMS provider (Twilio, AWS SNS, Vonage, etc.).
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
}

/**
 * Default in-memory transport for development and testing.
 * Stores all sent messages for later inspection.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: Array<SmsMessage & { messageId: string; sentAt: Date }> = [];

  async sendSms(message: SmsMessage): Promise<{ messageId: string }> {
    const messageId = `sms-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.sent.push({ ...message, messageId, sentAt: new Date() });
    return { messageId };
  }

  getSent(): Array<SmsMessage & { messageId: string; sentAt: Date }> {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

/**
 * E.164 phone number format: + followed by 1-15 digits.
 */
const PHONE_REGEX = /^\+[1-9]\d{1,14}$/;

/**
 * Validate that a string is a valid E.164 phone number.
 */
export function isValidPhoneNumber(phone: string): boolean {
  return PHONE_REGEX.test(phone);
}

/**
 * Format a NotificationPayload into a plain-text SMS body.
 * SMS messages are length-limited, so we keep it concise:
 * subject on its own line, then body.
 */
export function formatSmsBody(payload: NotificationPayload): string {
  return `${payload.subject}\n${payload.body}`;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private config: Required<Pick<SmsConfig, 'fromNumber' | 'maxRetries'>>;

  constructor(config: SmsConfig, transport?: SmsTransport) {
    this.config = {
      fromNumber: config.fromNumber,
      maxRetries: config.maxRetries ?? 2,
    };
    this.transport = transport ?? new InMemorySmsTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!isValidPhoneNumber(payload.recipient)) {
      this.logger.warn(`Invalid phone number: ${payload.recipient}`);
      return {
        success: false,
        notificationId: `sms-${Date.now()}`,
        channel: 'sms',
        error: `Invalid phone number: ${payload.recipient}`,
      };
    }

    const message: SmsMessage = {
      to: payload.recipient,
      from: this.config.fromNumber,
      body: formatSmsBody(payload),
    };

    let lastError: unknown;
    const maxAttempts = this.config.maxRetries + 1;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        const result = await this.transport.sendSms(message);
        this.logger.info(
          `SMS sent to ${payload.recipient}: "${payload.subject}" (messageId: ${result.messageId})`,
        );
        return {
          success: true,
          notificationId: result.messageId,
          channel: 'sms',
        };
      } catch (error) {
        lastError = error;
        this.logger.warn(
          `SMS send attempt ${attempt}/${maxAttempts} failed for ${payload.recipient}: ${error}`,
        );
      }
    }

    const errorMsg = lastError instanceof Error ? lastError.message : String(lastError);
    this.logger.error(
      `SMS delivery failed after ${maxAttempts} attempts to ${payload.recipient}: ${errorMsg}`,
    );
    return {
      success: false,
      notificationId: `sms-failed-${Date.now()}`,
      channel: 'sms',
      error: `Delivery failed after ${maxAttempts} attempts: ${errorMsg}`,
    };
  }

  /**
   * Get the underlying transport (useful for testing with InMemorySmsTransport).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
  isValidPhoneNumber,
  formatSmsBody,
} from '../../src/adapters/sms.adapter.js';
import type { SmsTransport } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+14155551234',
    subject: 'Order Update',
    body: 'Your order has shipped.',
    channel: 'sms',
    priority: 'normal',
    ...overrides,
  };
}

describe('isValidPhoneNumber', () => {
  it('should accept valid E.164 numbers', () => {
    expect(isValidPhoneNumber('+14155551234')).toBe(true);
    expect(isValidPhoneNumber('+442071234567')).toBe(true);
    expect(isValidPhoneNumber('+1')).toBe(false); // too short (only 1 digit after +)
    expect(isValidPhoneNumber('+12')).toBe(true);
  });

  it('should reject invalid phone numbers', () => {
    expect(isValidPhoneNumber('14155551234')).toBe(false); // missing +
    expect(isValidPhoneNumber('+0123456')).toBe(false); // starts with 0
    expect(isValidPhoneNumber('')).toBe(false);
    expect(isValidPhoneNumber('alice@example.com')).toBe(false);
    expect(isValidPhoneNumber('not-a-phone')).toBe(false);
    expect(isValidPhoneNumber('+1234567890123456')).toBe(false); // 16 digits, too long
  });
});

describe('formatSmsBody', () => {
  it('should format subject and body into plain text', () => {
    const payload = makePayload();
    const body = formatSmsBody(payload);

    expect(body).toBe('Order Update\nYour order has shipped.');
  });

  it('should handle empty body', () => {
    const payload = makePayload({ body: '' });
    const body = formatSmsBody(payload);

    expect(body).toBe('Order Update\n');
  });
});

describe('InMemorySmsTransport', () => {
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
  });

  it('should store sent messages', async () => {
    const result = await transport.sendSms({
      to: '+14155551234',
      from: '+18005551234',
      body: 'Hello',
    });

    expect(result.messageId).toBeTruthy();
    expect(transport.getSent()).toHaveLength(1);
    expect(transport.getSent()[0]?.to).toBe('+14155551234');
  });

  it('should clear sent messages', async () => {
    await transport.sendSms({ to: '+14155551234', from: '+18005551234', body: 'Hi' });
    transport.clear();
    expect(transport.getSent()).toHaveLength(0);
  });
});

describe('SmsAdapter', () => {
  let transport: InMemorySmsTransport;
  let adapter: SmsAdapter;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ fromNumber: '+18005551234' }, transport);
  });

  it('should have channel set to sms', () => {
    expect(adapter.channel).toBe('sms');
  });

  it('should send an SMS successfully', async () => {
    const payload = makePayload();
    const result = await adapter.send(payload);

    expect(result.success).toBe(true);
    expect(result.channel).toBe('sms');
    expect(result.notificationId).toBeTruthy();

    const sent = transport.getSent();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.to).toBe('+14155551234');
    expect(sent[0]?.from).toBe('+18005551234');
    expect(sent[0]?.body).toContain('Order Update');
    expect(sent[0]?.body).toContain('Your order has shipped.');
  });

  it('should fail for invalid phone number', async () => {
    const payload = makePayload({ recipient: 'not-a-phone' });
    const result = await adapter.send(payload);

    expect(result.success).toBe(false);
    expect(result.error).toContain('Invalid phone number');
    expect(transport.getSent()).toHaveLength(0);
  });

  it('should fail for email address used as recipient', async () => {
    const payload = makePayload({ recipient: 'alice@example.com' });
    const result = await adapter.send(payload);

    expect(result.success).toBe(false);
    expect(result.error).toContain('Invalid phone number');
  });

  it('should retry on transport failure and eventually fail', async () => {
    const failingTransport: SmsTransport = {
      sendSms: vi.fn().mockRejectedValue(new Error('SMS gateway timeout')),
    };
    const retryAdapter = new SmsAdapter(
      { fromNumber: '+18005551234', maxRetries: 2 },
      failingTransport,
    );

    const result = await retryAdapter.send(makePayload());

    expect(result.success).toBe(false);
    expect(result.error).toContain('Delivery failed after 3 attempts');
    expect(result.error).toContain('SMS gateway timeout');
    expect(failingTransport.sendSms).toHaveBeenCalledTimes(3);
  });

  it('should succeed on retry after initial failure', async () => {
    let callCount = 0;
    const flakyTransport: SmsTransport = {
      sendSms: vi.fn().mockImplementation(async () => {
        callCount++;
        if (callCount === 1) {
          throw new Error('Temporary failure');
        }
        return { messageId: 'sms-retry-success' };
      }),
    };
    const retryAdapter = new SmsAdapter(
      { fromNumber: '+18005551234', maxRetries: 2 },
      flakyTransport,
    );

    const result = await retryAdapter.send(makePayload());

    expect(result.success).toBe(true);
    expect(result.notificationId).toBe('sms-retry-success');
    expect(flakyTransport.sendSms).toHaveBeenCalledTimes(2);
  });

  it('should use InMemorySmsTransport by default', () => {
    const defaultAdapter = new SmsAdapter({ fromNumber: '+18005551234' });
    expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemorySmsTransport);
  });
});

describe('SmsAdapter integration with NotificationService', () => {
  it('should receive notifications routed through the service', async () => {
    const { EventBus } = await import('../../src/events/event-bus.js');
    const { NotificationService, resetNotificationIdCounter } = await import(
      '../../src/services/notification.service.js'
    );

    const eventBus = new EventBus();
    const service = new NotificationService(eventBus);
    resetNotificationIdCounter();

    const transport = new InMemorySmsTransport();
    const smsAdapter = new SmsAdapter({ fromNumber: '+18005551234' }, transport);
    service.registerAdapter(smsAdapter);

    // Send an SMS notification directly by emitting an event.
    // Note: current event handlers hardcode channel: 'email', so we verify
    // that the adapter works when channel is 'sms' by manually invoking send.
    const result = await smsAdapter.send({
      recipient: '+14155551234',
      subject: 'Welcome to TaskFlow Pro',
      body: 'Hi Alice, welcome!',
      channel: 'sms',
      priority: 'normal',
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    const sent = transport.getSent();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.to).toBe('+14155551234');
    expect(sent[0]?.body).toContain('Welcome to TaskFlow Pro');
  });
});

